#include<bits/stdc++.h>
using namespace std;
const int maxn=1e8+5;
int t,A[maxn];
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--){
		int n,m,k,a;
		cin>>n>>m>>k>>a;
		int minx=1000000005;
		for(int i=1;i<=n;i++){
			cin>>A[i];
		}
		for(int i=1;i<=k;i++){
			int l,r;
			cin>>l>>r;
			for(int j=l;j<=r;j++){
				A[i]++;
			}
		}
		for(int i=1;i<=n;i++){
			minx=min(A[i],minx);
		}
		cout<<minx<<"\n";
	}
	return 0;
}
